  describe('action contracts (PBT)', () => {
    it('register handles empty input: ', async () => {
      if (typeof conceptEntityHandler.register !== 'function') return;
      const storage = createInMemoryStorage();
      const result = await safeInvoke(async () => await interpret(conceptEntityHandler.register({  }), storage));
      // Empty input should produce a defined result with a variant
      expect(result).toBeDefined();
      if (result.variant !== undefined) {
        expect(typeof result.variant).toBe('string');
      }
    });

    it('register ensures on ok: ', async () => {
      if (typeof conceptEntityHandler.register !== 'function') return;
      let seen = false;
      await fc.assert(
        fc.asyncProperty(
          fc.record({ name: fc.string({ minLength: 1, maxLength: 50 }), source: fc.string({ minLength: 1, maxLength: 50 }), ast: fc.string({ minLength: 1, maxLength: 50 }) }),
          async (input) => {
            const storage = createInMemoryStorage();
            const result = await safeInvoke(async () => {
              const program = conceptEntityHandler.register(input as Record<string, unknown>);
              return interpret(program, storage);
            });
            if (result?.variant === "ok") {
              seen = true;
              expect(result.output).toBeDefined();
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

